+        let stream = stream::iter(vec![77]);
+        let rl = RateLimitedStream::new(stream, Duration::from_millis(50));
+        pin_mut!(rl);
+
+        let start = std::time::Instant::now();
+        assert_eq!(rl.next().await, Some(77));
